module LIFObuffer (
    input [3:0] dataIn,
    input RW,
    input EN,
    input Rst,
    input Clk,
    output reg EMPTY,
    output reg FULL,
    output reg [3:0] dataOut
);

reg [3:0] stack_mem [0:3];
reg [2:0] SP;

always @(posedge Clk) begin
    if (Rst) begin
        SP <= 4;
        EMPTY <= 1;
        FULL <= 0;
        dataOut <= 0;
    end else if (EN) begin
        if (!FULL && !RW) begin
            stack_mem[SP] <= dataIn;
            SP <= SP - 1;
            if (SP == 0)
                EMPTY <= 1;
            FULL <= (SP == 3) ? 1 : 0;
        end else if (!EMPTY && RW) begin
            dataOut <= stack_mem[SP];
            stack_mem[SP] <= 0;
            SP <= SP + 1;
            EMPTY <= (SP == 4) ? 1 : 0;
            FULL <= 0;
        end
    end
end

endmodule
